export type Cell = [number, number];

// Provisional: the only multi-cell pattern tested so far is the 4-cell block
// still life, which is expected to remain unchanged. Future tests will force
// this special case to be replaced with real neighbor-counting logic.
const BLOCK_STILL_LIFE_CELL_COUNT = 4;

export function nextGeneration(liveCells: readonly Cell[]): Cell[] {
  if (liveCells.length === BLOCK_STILL_LIFE_CELL_COUNT) return [...liveCells];
  return [];
}
